### Modal CSS

```css
.modal-overlay {
    position: fixed;
    inset: 0;
    background: rgba(0, 0, 0, 0.5);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 1000;
    padding: 20px;
    /* 動畫 */
    animation: fadeIn 0.2s ease;
}

.modal {
    background: white;
    border-radius: 12px;
    max-width: 500px;
    width: 100%;
    max-height: 90vh;
    overflow-y: auto;
    box-shadow: 0 24px 48px rgba(0, 0, 0, 0.2);
    animation: scaleIn 0.2s ease;
}

.modal-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 20px 24px;
    border-bottom: 1px solid #e5e7eb;
}

.modal-body {
    padding: 24px;
}

.modal-footer {
    padding: 16px 24px;
    border-top: 1px solid #e5e7eb;
    display: flex;
    justify-content: flex-end;
    gap: 12px;
}

.modal-close {
    background: none;
    border: none;
    cursor: pointer;
    padding: 8px;
    border-radius: 6px;
    transition: background 0.15s;
}
.modal-close:hover {
    background: #f3f4f6;
}

@keyframes fadeIn {
    from { opacity: 0; }
    to { opacity: 1; }
}
@keyframes scaleIn {
    from { transform: scale(0.95); opacity: 0; }
    to { transform: scale(1); opacity: 1; }
}
```


### 5 個必做行為

```text
1. 鎖背景捲動
   - 用戶開 modal 不該滾背景
   - 加 body.style.overflow = "hidden"

2. ESC 關閉
   - 鍵盤用戶必須
   - addEventListener("keydown", e => e.key === "Escape")

3. 點外面關閉
   - 點 overlay 關閉
   - 點 modal 本體不關

4. Focus trap
   - Tab 只在 modal 內循環
   - 不能 Tab 跳出去到背景

5. 開啟時 focus 第一個元素
   - close button 或第一個 input
   - 用戶能立刻操作
```


### React 完整實作

```tsx
import { useEffect, useRef } from "react";

interface ModalProps {
    isOpen: boolean;
    onClose: () => void;
    title: string;
    children: React.ReactNode;
}

function Modal({ isOpen, onClose, title, children }: ModalProps) {
    const modalRef = useRef(null);

    useEffect(() => {
        if (!isOpen) return;

        // 鎖捲動
        document.body.style.overflow = "hidden";

        // ESC 關
        const handleKey = (e: KeyboardEvent) => {
            if (e.key === "Escape") onClose();
        };
        window.addEventListener("keydown", handleKey);

        // Focus modal
        modalRef.current?.focus();

        return () => {
            document.body.style.overflow = "";
            window.removeEventListener("keydown", handleKey);
        };
    }, [isOpen, onClose]);

    if (!isOpen) return null;

    return (

